chart.options:
chart: {
  height: 350,
  width: 600,
  type: 'line',
},
plotOptions: {
  line: {
    isSlopeChart: true,
  },
},
title: {
  text: 'Regional Sales Rank by Quarter'
},
tooltip: {
  followCursor: true,
  intersect: false,
  shared: true,
},
dataLabels: {
  background: {
    enabled: true,
  },
  formatter(val, opts) {
    const seriesName = opts.w.config.series[opts.seriesIndex].name
    return val !== null ? seriesName : ''
  },
},
yaxis: {
  show: true,
  labels: {
    show: true,
  },
},
xaxis: {
  position: 'bottom',
},
legend: {
  show: true,
  position: 'top',
  horizontalAlign: 'left',
},
stroke: {
  width: [2, 3, 4, 2],
  dashArray: [0, 0, 5, 2],
  curve: 'smooth',
}
